---@class LBlockMiniGameMoveActor
local LBlockMiniGameMoveActor = LxClass("LBlockMiniGameMoveActor", nil)
----------------------------------------------------------------
-----------------------------------------------------------------
function LBlockMiniGameMoveActor:LBlockMiniGameMoveActor(obj, path)
    self._obj        = obj
    self._path       = path

    self._tarPos     = nil
    self._endTime    = 0
    self._isMoving   = false
    self._index      = 1

    local ref        = self._obj:GetData():GetMonsterRef()
    self._onePosTime = 1000 / ref.walkSpeed

    self._isTower    = self._obj:IsTower()
    self._isInEnd    = false
end

-- 销毁
function LBlockMiniGameMoveActor:Destroy()
end

function LBlockMiniGameMoveActor:Update(dt)
    if self._isTower then return end

    if not self._isMoving then return end

    if self._needInitMove then return end

    self._endTime = self._endTime - dt

    if self._endTime <= 0 then
        self:StartMove()
    end
end

function LBlockMiniGameMoveActor:ReadyInitMove()
    self._needInitMove = true
    self._index = 2
    local nextTab = self._path[self._index]

    local trans = self._obj:GetTransform()
    local curPos = trans.position
    local dis = Vector3.Distance(curPos, nextTab.pos)
    local time = dis * self._onePosTime

    curPos.z = 0
    trans.position = curPos
    self._obj:UpDateFlipX(self._path[1].flipX)
    self:MoveTo(nextTab.pos, time)
end

function LBlockMiniGameMoveActor:StartMove()
    if self._isTower then return end

    local pos, time = self:PopNextPos()
    if pos == nil then
        self:StopMove(true)
        return
    end

    self:MoveTo(pos, time)
end

function LBlockMiniGameMoveActor:MoveTo(pos, time)
    local btObjectView = self._obj:GetBtObjectView()
    if not btObjectView then return end

    local tarPos = pos:Clone()
    btObjectView:StartMove(tarPos, time)
    self._isMoving = true
    self._endTime = time
    self._tarPos = tarPos:Clone()

    self._obj:GetAniActor():PlayRun()
    self._needInitMove = nil
end

function LBlockMiniGameMoveActor:MoveToRight(pos)
    local btObjectView = self._obj:GetBtObjectView()
    if not btObjectView then return end

    local trans = self._obj:GetTransform()
    local curPos = trans.position
    local dis = Vector3.Distance(curPos, pos)
    local time = dis * self._onePosTime

    self:MoveTo(pos, time)

    self._needInitMove = true
    self._obj:UpDateFlipX(false)
end

-- 是否需要初始化移动
function LBlockMiniGameMoveActor:NeedInitMove()
    return self._needInitMove
end

function LBlockMiniGameMoveActor:StopMove(bEnd)
    local btObjectView = self._obj:GetBtObjectView()
    if not btObjectView then return end

    if (not self._isMoving) then return end
    self._isMoving = false
    btObjectView:StopMove(bEnd)

    self._obj:GetAniActor():PlayIdle()
end

function LBlockMiniGameMoveActor:IsMoving()
    return self._isMoving
end

-- 暂停移动
function LBlockMiniGameMoveActor:PauseMove()
    if self._isTower then return end

    self:OnPauseGame()
end

-- 恢复移动
function LBlockMiniGameMoveActor:ResumeMove()
    if self._isTower then return end

    self:OnResumeGame()
end

-- 暂停
function LBlockMiniGameMoveActor:OnPauseGame()
    local btObjectView = self._obj:GetBtObjectView()
    if btObjectView then
        btObjectView:TimePause()
    end

    self._isMoving = false
end

-- 恢复
function LBlockMiniGameMoveActor:OnResumeGame()
    local btObjectView = self._obj:GetBtObjectView()
    if btObjectView then
        btObjectView:TimeResume()
    end
    self._isMoving = true
end

-- 获取第一个位置
function LBlockMiniGameMoveActor:GetFirstPos()
    return self._path[1].pos
end

-- true: 已达终点
function LBlockMiniGameMoveActor:IsInEnd()
    return self._isInEnd
end

-- 弹出下一个位置, nil 表示已经是终点了
function LBlockMiniGameMoveActor:PopNextPos()
    local curTab = self._path[self._index]
    local nextTab = self._path[self._index + 1]
    if nextTab == nil then
        self._isInEnd = true
        return nil, 0
    end
    self._index = self._index + 1

    self._obj:UpDateFlipX(curTab.flipX)

    local dis = Vector3.Distance(curTab.pos, nextTab.pos)
    return nextTab.pos, dis * self._onePosTime
end

return LBlockMiniGameMoveActor
